from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a written work into a single fluent sentence.
    """
    if not triples:
        return ""

    # Helper to clean object strings (remove surrounding quotes)
    def clean(obj: str) -> str:
        return obj.strip('\"')

    # Determine the main written work (subject of the first triple)
    main_work = triples[0].subject

    # Collect predicates for the main work
    work_info = {}
    for t in triples:
        if t.subject == main_work:
            work_info[t.predicate] = clean(t.object)

    # Identify the author if present
    author_name = work_info.get("author")
    author_info = {}
    if author_name:
        for t in triples:
            if t.subject == author_name:
                author_info[t.predicate] = clean(t.object)

    # Build parts of the sentence for the main work
    parts = []

    # Title and genre
    title_part = main_work
    if "genre" in work_info:
        title_part += f", a {work_info['genre']}"
    elif "literaryGenre" in work_info:
        title_part += f", a {work_info['literaryGenre']}"
    parts.append(title_part)

    # Author
    if author_name:
        parts.append(f"written by {author_name}")

    # Language
    if "language" in work_info:
        parts.append(f"in {work_info['language']}")

    # Publisher and country
    pub_parts = []
    if "publisher" in work_info:
        pub_parts.append(work_info["publisher"])
    if "country" in work_info:
        pub_parts.append(work_info["country"])
    if pub_parts:
        parts.append("published by " + " in ".join(pub_parts))

    # Publication year
    if "firstPublicationYear" in work_info:
        parts.append(f"in {work_info['firstPublicationYear']}")

    # ISBN / ISSN etc.
    if "isbnNumber" in work_info:
        parts.append(f"ISBN {work_info['isbnNumber']}")
    if "issnNumber" in work_info:
        parts.append(f"ISSN {work_info['issnNumber']}")
    if "eissnNumber" in work_info:
        parts.append(f"e‑ISSN {work_info['eissnNumber']}")

    # Page count
    if "numberOfPages" in work_info:
        parts.append(f"{work_info['numberOfPages']} pages")

    # Media type
    if "mediaType" in work_info:
        parts.append(f"available as {work_info['mediaType']}")

    # Followed / preceded
    if "followedBy" in work_info:
        parts.append(f"followed by {work_info['followedBy']}")
    if "precededBy" in work_info:
        parts.append(f"preceded by {work_info['precededBy']}")

    # Additional work‑specific details
    extra_keys = [
        "releaseDate", "impactFactor", "codenCode", "LCCN_number",
        "abbreviation", "academicDiscipline", "libraryofCongressClassification",
        "oclcNumber", "frequency"
    ]
    for k in extra_keys:
        if k in work_info:
            parts.append(f"{k.replace('_', ' ')} {work_info[k]}")

    # Author‑related clauses
    if author_info:
        author_parts = []
        if "almaMater" in author_info:
            author_parts.append(f"studied at {author_info['almaMater']}")
        if "doctoralAdvisor" in author_info:
            author_parts.append(f"was advised by {author_info['doctoralAdvisor']}")
        if "nationality" in author_info:
            author_parts.append(f"is {author_info['nationality']}")
        if "residence" in author_info:
            author_parts.append(f"lives in {author_info['residence']}")
        if "birthPlace" in author_info:
            author_parts.append(f"was born in {author_info['birthPlace']}")
        if "birthDate" in author_info:
            author_parts.append(f"was born on {author_info['birthDate']}")
        if author_parts:
            parts.append(f"The author {author_name} " + ", ".join(author_parts))

    # Combine all parts into a single fluent sentence
    sentence = ", ".join(parts) + "."

    # Ensure first character is capitalized
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END
